import{_ as n,o as r,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const s="/images/uebung087.jpg",a="/images/uebung088.jpg",m=JSON.parse('{"title":"Übung Lektion 52","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung52.md","filePath":"lektionen/uebung52.md"}'),l={name:"lektionen/uebung52.md"};function o(d,e,u,b,h,c){return r(),t("div",null,[...e[0]||(e[0]=[i('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-52" tabindex="-1">Übung Lektion 52 <a class="header-anchor" href="#ubung-lektion-52" aria-label="Permalink to &quot;Übung Lektion 52&quot;">​</a></h1><p>१. मनुस्मृति ४, १५९ - १६१</p><p>यद्यत्परवशं कर्म<br> ततद्यत्नेन वर्जयेत् ।<br> यद्यदात्मवशं तु स्यात्<br> ततत्सेवेत यत्नतः ॥१५९॥</p><blockquote><p>Jede Tat, die auf fremdem Willen beruht, vermeide man eifrig, was aber aus eigenem Willen geschieht, das pflege man eifrig.</p></blockquote><p>सर्वं परवशं दुःखं<br> सर्वमात्मवशं सुखम् ।<br> एतद्विद्यात्समासेन<br> लक्षणं सुखदुःखयोः ॥१६०॥</p><blockquote><p>Alles, was auf fremdem Willen beruht ist leidvoll, alles was auf eigenem Willen beruht ist Glück. Das soll man zusammengefasst als Merkmal von Glück und Leid kennen.</p></blockquote><p>यत्कर्म कुर्वतो ऽस्य स्यात्<br> परितोषो ऽन्तरात्मनः ।<br> तत्प्रयत्नेन कुर्वीत<br> विपरीतं तु वर्जयेत् ॥१६१॥</p><blockquote><p>Was, wenn man es tut, zur inneren Befriedigung gereicht, das soll man eifrig tun, Gegenteiliges aber unterlasse man.</p></blockquote><p><img src="'+s+'" alt=""><br> Abb.: सर्वं परवशं दुःखम्<br> विद्यारम्भः<br> [Bildquelle: ToreaJade. -- <a href="http://www.flickr.com/photos/toreajade/52085380/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/toreajade/52085380/</a>. -- Zugriff am 2009-01-26. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, share alike)]</p><p>२. मनुस्मृति २, ६ Über die Quellen des धर्म</p><p>वेदो ऽखिलो धर्ममूलम्<br> स्मृतिशीले च तद्विदाम् ।<br> आचआरश्चैव साधूनाम्<br> आत्मनस्तुष्टिरेव च ॥६॥</p><blockquote><p>Wurzel des Dharma ist</p><ul><li><p>der ganzen Veda</p></li><li><p>die Überlieferung und die Sitte der Vedakundigen</p></li><li><p>das Verhalten der Guten</p></li><li><p>die Zufriedenheit der Seele</p></li></ul></blockquote><p>Erklärung siehe:</p><p>३. कौटिलीयार्थशास्त्र १, ७, २ - ७ Über अर्थ, काम, धर्म im Leben des Fürsten</p><p>एवं वश्येन्द्रियः परस्त्रीद्रव्यहिंसाश्च वर्जयेत्, स्वप्नं लौल्यमनृतमुद्धतवेषत्वमनर्थ्यसंयोगमधर्मसंयुक्तमनर्थसंयुक्तं च व्यवहारम् ।२। धर्मार्थाविरोधेन कामं सेवेत, न निःसुखः स्यात् ।३। समं वा त्रिवर्गमन्योन्यानुबद्धम् ।४। एको ह्यत्यासेवितो धर्मार्थकामानामात्मानमितरौ च पीदयति ।५। अर्थ एव प्रधान इति कौटिल्यः ।६। अर्थमूलौ हि धर्मकामाविति ।७।</p><blockquote><p>So halte er seine Sinne unter Kontrolle, meide fremde Frauen, fremdes Gut und Gewalt, und vermeide Schlaf, Lüsternheit, Lüge, Geckenhaftigkeit, Unnützes und unrechte oder unnütze Geschäfte. Er gebe sich der Lust hin ohne dass dadurch Recht und zweckrationales Verhalten gestört wird, er sei nicht freudlos. Oder er pflege gleichmäßig alle drei Lebensziele, die miteinander verbunden sind. Wenn man sich nämlich einem von Recht und Sitte, zweckrationalem Verhalten und Lust übermäßig hingibt, dann bedrückt das die Seele und die beiden anderen. Kauṭilya sagt, dass zweckrationales Verhalten das Wichtigste ist. Recht und Sitte sowie Lust wurzeln nämlich in zweckrationalem Handeln.</p></blockquote><p>४. अश्वघोष (2. Jhdt. n. Chr.): बुद्धचरित ४ Buddhas erlösende Erkenntnis</p><p>ततो मारबलं जित्वा<br> धैर्येण च शमेन च ।<br> परमार्थं विजिज्ञासुः<br> स दद्ध्यौ ध्यानकोविदः ॥१॥</p><blockquote><p>Als er mit Festigkeit und Ruhe das Heer Māras besiegt hatte, wollte der in Meditation Erfahrene die höchste Wahrheit und Wirklichkeit völlig erkennen und meditierte.</p></blockquote><p>सर्वेषु ध्यानविधिषु<br> प्राप्य चैश्वर्यमुत्तमम् ।<br> सस्मार प्रथमे याम<br> पूर्वजन्मपरंपराम् ॥२॥</p><blockquote><p>Er brachte es zur höchsten Meisterschaft in allen Meditationsmethoden und erinnerte sich in der ersten Nachtwache an die ununterbrochene Abfolge seiner Wiedergeburten.</p></blockquote><p>अमुत्राहमयं नाम<br> च्युतस्तस्मादिहागतः ।<br> इति जन्मसहस्राणि<br> सस्मारानुभवन्निव ॥३॥</p><blockquote><p>&quot;Dort war ich der So-und-so, von dort geschieden bin ich hierher gekommen&quot; so erinnerte er sich an Tausende von Geburten so als ob er sie erfahren würde.</p></blockquote><p>स्मृत्वा जन्म च मृत्युं च<br> तासु तासूपपत्तिषु ।<br> ततः सत्त्वेषु कारुण्यम्<br> चकार करुणात्मकः ॥४॥</p><blockquote><p>Als er sich so Geburt und Tod in diesen verschiedenen Existenzen erinnert hatte, entfaltete er gegenüber den Wesen Mitgefühl, er, dessen Wesen Mitgefühl ist.</p></blockquote><p>कृत्वेह स्वजनोत्सर्गम्<br> पुनरन्यत्र च कृत्वा ।<br> अत्राणः खलु लोको ऽयम्<br> परिभ्रमति चक्रवत् ॥५॥</p><blockquote><p>Wahrlich, diese Welt ist ohne Rettung und irrt herum wie ein Rad: sie entlässt ihre Geschöpfe hier und dann wieder dort.</p></blockquote><p>इत्येवं स्मरतस्तस्य<br> बभूव नियतात्मनः ।<br> कदलीगर्भनिःसारः<br> संसार इति निश्चयः ॥६॥</p><blockquote><p>Als er sich entschlossenen Herzens so erinnerte kam er zur festen Erkenntnis: Der Lauf der Wiedergeburten ist ohne Mark und Kern wie das Innere einer Bananenpflanze.</p></blockquote><p>द्वितीये त्वागते यामे<br> सो ऽद्वितीयपराक्रमः ।<br> दिव्यं लेभे परं चक्षुः<br> सर्वचक्षुष्मतां वरः ॥७॥</p><blockquote><p>Als die zweite Nachtwache gekommen war, hat er, dessen Macht wie die keines zweiten ist, das höchste himmlische Auge bekommen, er, der Beste aller, die ein Auge haben.</p></blockquote><p>ततस्तेन स दिव्येन<br> परिशुद्धेन चक्षुषा ।<br> ददर्श निखिलं लोकम्<br> आदर्श इव निर्मले ॥८॥</p><blockquote><p>Dann sah er mit diesem völlig reinen himmlischen Auge die ganze Welt wie in einem makellosen Spiegel.</p></blockquote><p>सत्त्वानां पश्यतस्तस्य<br> निकृष्टोत्कृष्टकर्मणाम् ।<br> प्रच्युतिं चोपपत्तिं च<br> ववृधे करुणात्मता ॥९॥</p><blockquote><p>Als er das Vergehen und Entstehen der Wesen sah, die gutes oder schlechtes Karma hatten, da wuchs das Mitgefühl in seinem Herzen.</p></blockquote><p>इमे दुष्कृतकर्माणः<br> प्राणिनो यान्ति दुर्गतिम् ।<br> इमे ऽन्ये शुभकर्माणः<br> प्रतिष्ठन्ते त्रिविष्टपे ॥१०॥</p><blockquote><p>Diese Lebewesen, die böse Taten begangen haben, gehen in eine schlechte Existenz, diese anderen, die gutes Karma haben, entstehen wieder in Indras Himmel.</p></blockquote><p><img src="'+a+'" alt=""><br> Abb.: कदलीगर्भनिःसारः<br> Querschnitt durch eine Bananenpflanze<br> [Bildquelle: : Przemyslaw &quot;Blueshade&quot; Idzkiewicz. -- Wikimedia Commons. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, share alike)]</p><p>Zu den <a href="./uebung54">Lösungen der Übungen 54 - 57</a></p>',40)])])}const g=n(l,[["render",o]]);export{m as __pageData,g as default};
